INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$AI site generation (Airo)$q$, $q$Generates a starter website, layout, and marketing copy from a short description of the business, speeding up initial setup.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Drag-and-drop editor$q$, $q$Visual, no-code editor with responsive templates that automatically adapt to mobile and desktop screens.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Built-in SEO tools$q$, $q$Handles meta titles, descriptions, and basic technical SEO without needing a separate plugin or service.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Email and social marketing$q$, $q$Send email campaigns and schedule or respond to social media posts directly from the site dashboard, with allowances that scale by plan.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Appointment booking$q$, $q$Recurring booking and scheduling tools built into the Premium and Ecommerce tiers for service-based businesses.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Ecommerce and marketplace sync$q$, $q$Product listings, flexible payment options, shipping configuration, and synced selling on Amazon, eBay, and Etsy on the top tier.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Managed hosting and SSL$q$, $q$GoDaddy handles hosting, backups, and free SSL certificates, with no server management required from the user.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Built-in analytics$q$, $q$A visitor and engagement dashboard included in every plan without needing to configure a separate analytics tool.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Very fast, beginner-friendly setup with no coding required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Affordable entry-level pricing compared to hiring a designer or developer$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Hosting, domain, marketing, and ecommerce bundled into one subscription$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Large-scale 24/7 customer support backed by GoDaddy's infrastructure$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$AI-assisted site generation (Airo) speeds up the first draft of a new site$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Less design flexibility and customization than Wix, Squarespace, or WordPress$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Renewal pricing can rise noticeably after an introductory promotional period$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Ecommerce features are less advanced than dedicated platforms like Shopify$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$No code export or data portability if you want to leave the platform later$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Extra email sends and add-ons can increase the effective monthly cost$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Is GoDaddy Website Builder free?$q$, $q$There is a free trial to test the editor, but publishing a live site requires one of the paid monthly plans starting around 9.99 dollars a month; there is no permanently free published-site tier.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Can I connect my own domain to GoDaddy Website Builder?$q$, $q$Yes, custom domain connection is included on all paid plans, and it integrates directly with domains purchased through GoDaddy.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Does GoDaddy Website Builder support online stores?$q$, $q$Yes, the Ecommerce plan adds unlimited product listings, flexible payment options, shipping configuration, and marketplace sync to Amazon, eBay, and Etsy.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Can I cancel my GoDaddy Website Builder subscription anytime?$q$, $q$Plans are billed monthly with no long-term contract required, so you can cancel at any time, though annual commitments may offer a lower promotional rate.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Does GoDaddy Website Builder use AI?$q$, $q$Yes, GoDaddy Airo is an AI feature that generates a starter site, layout, and marketing copy based on a short description of your business.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$How does GoDaddy Website Builder compare to WordPress?$q$, $q$Website Builder is a fully managed, no-code, drag-and-drop platform, while WordPress is a self-hosted content management system offering far more customization at the cost of more setup and technical maintenance.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Launching a small business website fast$q$, $q$A local business owner uses the AI-assisted editor to go from no website to a live, mobile-friendly site in under an hour.$q$, $q$Small business owners and solo entrepreneurs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Service booking for consultants and salons$q$, $q$A service provider uses the Premium plan's recurring appointment booking to let clients schedule and pay online.$q$, $q$Consultants, salons, coaches, and freelancers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Small-catalog online store$q$, $q$A merchant with a limited product catalog uses the Ecommerce plan to sell directly and sync listings to Amazon, eBay, and Etsy.$q$, $q$Small ecommerce sellers and makers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Basic$q$, $q$$9.99/month$q$, $q$Monthly$q$, NULL, $q$["Analytics dashboard","Custom domain connection","Email marketing","Social media marketing","Drag-and-drop website editor"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Standard$q$, $q$$11.99/month$q$, $q$Monthly$q$, NULL, $q$["Everything in Basic","Built-in SEO tools","20 social posts and responses per month","500 email marketing sends per month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Premium$q$, $q$$14.99/month$q$, $q$Monthly$q$, NULL, $q$["Everything in Standard","Recurring appointment booking","Unlimited social posts and responses","25,000 email marketing sends per month"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Ecommerce$q$, $q$$20.99/month$q$, $q$Monthly$q$, NULL, $q$["Everything in Premium","Unlimited product listings","Flexible payment options","Shipping configuration","Discount and promotional tools","Marketplace sync to Amazon, eBay, and Etsy"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GoDaddy Website Builder is a fully hosted, no-code website platform built by GoDaddy, the Tempe, Arizona company founded in 1997 that is also the world's largest domain registrar. It targets small businesses and solo entrepreneurs who want to publish a professional website quickly without managing hosting, security, or code.$q$, $q$The platform combines a drag-and-drop visual editor with GoDaddy Airo, an AI assistant that generates an initial site layout, copy, and branding from a short description of the business, then lets users refine the result manually.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Beyond site design, Website Builder bundles marketing tools directly into the editor: built-in SEO controls, scheduled social media posting, and email marketing campaigns, all managed from the same dashboard as the site itself.$q$, $q$Higher-tier plans add business operations features such as recurring appointment booking for service providers and a full ecommerce toolkit, including product catalogs, payment processing, shipping rules, and marketplace sync to Amazon, eBay, and Etsy.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Website Builder uses a four-tier monthly subscription model ranging from a Basic plan around 9.99 dollars a month up to an Ecommerce plan around 20.99 dollars a month, with each tier unlocking higher marketing send limits and more advanced commerce or booking features.$q$, $q$GoDaddy offers a free trial to test the editor, but there is no permanently free published plan, and reviewers note that renewal pricing after an introductory period can increase, so it is worth confirming the ongoing rate before subscribing long term.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
