INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
