INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Assignment creation and distribution$q$, $q$Teachers create, schedule, and distribute assignments organized by topic and due date.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Rubric-based grading$q$, $q$Consistent scoring criteria applied across a class, streamlining grading workflows.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Originality reports$q$, $q$Scans student submissions for potential plagiarism against web sources and prior student work.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Deep Google Workspace integration$q$, $q$Works natively with Drive, Docs, Sheets, Slides, Forms, Calendar, and Meet for a unified instructional workflow.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Class stream and announcements$q$, $q$A central feed for class announcements, discussion, and material sharing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Parent and guardian email summaries$q$, $q$Automated email digests keep families informed of upcoming and missing work without a separate login.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Gemini AI suggestions$q$, $q$AI-generated help for drafting assignment instructions, discussion questions, and writing feedback.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Google Workspace for Education tiers$q$, $q$Paid add-ons (Teaching and Learning Upgrade, Standard, Plus) unlock expanded originality reports and advanced assessment tools.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Free for individuals and qualifying schools under Education Fundamentals$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Deep, seamless integration with the widely used Google Workspace suite$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Simple, low-friction interface that is easy for teachers and students to adopt$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Gemini AI integration adds assignment and feedback assistance$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Works across web, iOS, and Android, fitting varied school device programs$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Less advanced gradebook and curriculum-mapping tools than dedicated LMS platforms like Canvas or Schoology$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Limited originality reports (five per class) on the free Fundamentals tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Paid tiers and their features can be confusing given recent 2025 licensing restructuring$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$District-level reporting and compliance tools are less robust than enterprise LMS competitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Requires deep buy-in to the Google ecosystem, which can be a lock-in concern for some districts$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Is Google Classroom free?$q$, $q$Yes, Google Classroom is free for any individual Google account holder, and Education Fundamentals remains free for qualifying schools, though paid Google Workspace for Education tiers add expanded features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$When was Google Classroom launched?$q$, $q$Google Classroom launched in August 2014 as part of what was then called Google Apps for Education.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Does Google Classroom include AI features?$q$, $q$Yes, Google has integrated its Gemini AI assistant into Classroom to help with drafting assignments, generating discussion questions, and offering writing feedback suggestions.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$How much does the Google Workspace for Education Teaching and Learning Upgrade cost?$q$, $q$It is priced at approximately 4.80 dollars per staff license per month, or roughly 48 dollars annually when billed yearly.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$What is included in Education Fundamentals?$q$, $q$Education Fundamentals is the free tier and includes basic assignment creation, rubric-based grading, a limited number of originality reports per class, and baseline Gemini suggestions.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$How does Google Classroom compare to Canvas or Schoology?$q$, $q$Classroom is simpler and free, while Canvas and Schoology offer deeper gradebook, curriculum-mapping, and district-reporting functionality at real licensing cost.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$K-12 classroom assignment management$q$, $q$A teacher posts assignments, collects submissions through Drive, and grades using rubrics, all within Classroom.$q$, $q$K-12 teachers and students$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Remote and hybrid learning$q$, $q$A school uses Classroom paired with Google Meet to run live and asynchronous lessons for remote students.$q$, $q$Schools running hybrid or remote instruction$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Independent tutoring and homeschooling$q$, $q$An independent tutor or homeschooling parent uses the free consumer version of Classroom to organize lessons and assignments.$q$, $q$Independent tutors and homeschooling families$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Education Fundamentals$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Basic assignment creation and distribution","Rubric-based grading","Limited originality reports (5 per class)","Baseline Gemini suggestions"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Teaching and Learning Upgrade$q$, $q$$4.80/staff license/month$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Fundamentals","Expanded originality reporting","Advanced assessment and gradebook tools"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Education Standard$q$, $q$Custom (via reseller)$q$, $q$Annual$q$, NULL, $q$["Advanced security and device management","Enhanced admin controls"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Education Plus$q$, $q$~$5/student/year$q$, $q$Annual$q$, NULL, $q$["Everything in Standard and Teaching and Learning Upgrade","Advanced analytics and reporting","Expanded Gemini AI access"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Google Classroom is a free, cloud-based learning management system launched by Google in August 2014 as part of Google Apps for Education, now known as Google Workspace for Education. It is operated from Google's Mountain View, California headquarters under Alphabet Inc.$q$, $q$Rather than a standalone LMS, Classroom is a workflow layer on top of Google Workspace, integrating with Drive, Docs, Forms, Calendar, and Meet so a teacher's entire instructional workflow can happen within the Google ecosystem.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include assignment creation and distribution, rubric-based grading, originality (plagiarism) reports, class streams for announcements, and parent or guardian email summaries of student progress.$q$, $q$Google has integrated its Gemini AI assistant into Classroom, offering AI-generated suggestions for drafting assignments, discussion questions, and writing feedback.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Google Classroom is free for any individual Google account holder, and Education Fundamentals remains free for qualifying schools, including basic assignment tools, rubric grading, and limited originality reports.$q$, $q$Paid Google Workspace for Education tiers add more capability: the Teaching and Learning Upgrade runs about 4.80 dollars per staff license per month, Education Plus has historically run about 5 dollars per student per year, and Education Standard pricing is available through authorized resellers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
