INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Compute Engine and Kubernetes Engine$q$, $q$Virtual machines and managed Kubernetes for running and scaling containerized and traditional workloads.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Cloud Run serverless containers$q$, $q$Serverless container platform for deploying applications without managing underlying infrastructure.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$BigQuery data warehouse$q$, $q$Serverless, highly scalable data warehouse widely adopted for enterprise analytics, including as the export destination for Google Analytics data.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Spanner globally distributed database$q$, $q$Google's globally distributed, strongly consistent relational database for large-scale applications.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Vertex AI platform$q$, $q$Unified platform for training, deploying, and managing machine learning models at scale.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Gemini model access$q$, $q$Direct API access to Google's Gemini family of large language models for building generative AI applications.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Custom TPU hardware$q$, $q$Google-designed Tensor Processing Units offering differentiated price-performance for AI training and inference versus GPU-only competitors.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Global network and free tier$q$, $q$Google's global fiber network backbone paired with a genuine free tier and trial credit for new users to experiment before paying.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Fastest revenue growth rate among the three major hyperscale cloud providers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Strong data analytics offering through BigQuery, widely adopted across the industry$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Differentiated AI infrastructure with custom TPU hardware and Gemini model access$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Genuine free tier and trial credit for developers to experiment before committing$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Runs on the same global infrastructure that powers Google Search, Gmail, and YouTube$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Still the third-largest hyperscaler by market share behind AWS and Microsoft Azure$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Pricing complexity makes it hard to predict costs without careful planning or negotiation$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Smaller enterprise sales and support footprint in some regions compared to AWS and Azure$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$No flat subscription pricing; usage-based billing can be unpredictable for variable workloads$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Some services have historically had a shorter support lifecycle or deprecation risk versus competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$When was Google Cloud Platform founded?$q$, $q$Google Cloud traces its origin to April 2008, when Google previewed App Engine; it became an official, fully supported product in November 2011.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Is Google Cloud free to use?$q$, $q$Google Cloud offers a free tier and trial credit for core services like Compute Engine, Cloud Storage, and BigQuery, but usage beyond free thresholds is billed on a pay-as-you-go basis.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$What is Google Cloud's market share compared to AWS and Azure?$q$, $q$As of late 2025, Google Cloud holds roughly 13 percent of the global cloud infrastructure market, behind AWS at about 29 percent and Microsoft Azure at about 20 percent.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$What is Vertex AI?$q$, $q$Vertex AI is Google Cloud's unified platform for training, deploying, and managing machine learning models, including direct access to Google's Gemini large language models.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$How fast is Google Cloud growing?$q$, $q$Google Cloud revenue reached approximately 20 billion dollars in Q1 2026, up 63 percent year-over-year, the fastest growth rate among the major hyperscale cloud providers.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$What makes Google Cloud different from AWS and Azure?$q$, $q$Google Cloud differentiates through its BigQuery data analytics platform, its Vertex AI and Gemini AI stack, and custom Tensor Processing Unit (TPU) hardware for AI workloads.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Building and scaling web applications$q$, $q$A startup uses Compute Engine and Cloud Run to launch an application and scale it automatically as traffic grows.$q$, $q$Startups and individual developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Enterprise data analytics$q$, $q$An enterprise data team uses BigQuery to run large-scale SQL analytics across billions of rows of business data.$q$, $q$Enterprise data and analytics teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Generative AI application development$q$, $q$A product team builds a generative AI feature using Vertex AI and direct access to Google's Gemini models.$q$, $q$AI and machine learning engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Free Tier and Trial$q$, $q$Free (with usage limits and trial credit)$q$, $q$N/A$q$, NULL, $q$["Limited free usage of Compute Engine, Cloud Storage, and BigQuery","Free trial credit for new accounts","Access to core Google Cloud console and tools"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Pay-As-You-Go$q$, $q$Usage-based$q$, $q$Monthly (billed per usage)$q$, NULL, $q$["Billing per second or per resource unit consumed","Access to the full Google Cloud service catalog","Sustained-use discounts for consistent workloads"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Enterprise Committed-Use$q$, $q$Custom (negotiated)$q$, $q$Multi-year contract$q$, NULL, $q$["Custom committed-use discounts","Dedicated enterprise support","Volume-based pricing negotiated directly with Google sales"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Google Cloud Platform traces its origin to April 2008, when Google previewed App Engine, a developer platform letting external developers run applications on Google's infrastructure. App Engine became an official, fully supported product in November 2011, marking the emergence of what is now Google Cloud Platform.$q$, $q$Operated by Alphabet Inc. from Mountain View, California, Google Cloud reported approximately 20 billion dollars in Q1 2026 revenue, up 63 percent year-over-year, the fastest growth rate among the three major hyperscale cloud providers, though it remains third in global market share behind AWS and Microsoft Azure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Google Cloud's portfolio spans compute (Compute Engine, Google Kubernetes Engine, Cloud Run), storage and databases (Cloud Storage, Cloud SQL, Spanner, Bigtable, Firestore), and data analytics anchored by BigQuery, its widely adopted serverless data warehouse.$q$, $q$Its fastest-growing area is AI and machine learning, centered on Vertex AI, direct access to Google's Gemini models, and custom Tensor Processing Unit (TPU) hardware that differentiates it from GPU-reliant competitors.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Google Cloud uses standard pay-as-you-go, usage-based billing calculated per resource consumed, with a free tier and free trial credit letting new users experiment with core services like Compute Engine, Cloud Storage, and BigQuery before billing starts.$q$, $q$There is no single flat subscription price for the platform; costs vary by service, region, and commitment level, with enterprise customers typically negotiating custom committed-use discounts directly with Google sales.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
